import React, { useEffect, useState } from "react";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWRadioGroup from "../../../../component-widget/FAWRadioGroup";
import FAWDropdown from "../../../../component-widget/FAWDropdown";
import EditorSection from "./shared/EditorSection";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorShell from "./shared/EditorShell";

export default function QueSelfIdentificationItemEditor({ data, onSave, onClose, saveRef, isDefaultLanguage = true }) {
  const [item, setItem] = useState(
    data || {
      name: "",
      text: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      allowAnonymous: false,
      allowSelfIdentify: false,
      enableFirstName: false,
      enableLastName: false,
      enableEmail: false,
      enablePhone: false,
      enableDOB: false,
      enableUserName: false,
      enableContactTime: false,
    }
  );
  useEffect(()=>{ if (data) setItem(prev=>({ ...prev, ...data })); }, [data]);
  const set = (k, v) => setItem(prev=>({ ...prev, [k]: v }));
  const handleSave = () => { 
    onSave?.(item); 

  };
  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields item={item} onChange={set} isDefaultLanguage={isDefaultLanguage} questionType="SelfIdentificationItemType" />
      
      <EditorSection title="Self Identification Settings">
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          <FAWRadioGroup
            label="Allow Anonymous"
            value={item.allowAnonymous ? "Yes" : "No"}
            options={[
              { label: "Yes", value: "Yes" },
              { label: "No", value: "No" }
            ]}
            onChange={(value) => set('allowAnonymous', value === "Yes")}
          />
          
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, minmax(200px, 1fr))', gap: 12 }}>
            <FAWCheckbox label="Show First Name" checked={!!item.enableFirstName} onChange={e=> set('enableFirstName', e.target.checked)} />
            <FAWCheckbox label="Show Last Name" checked={!!item.enableLastName} onChange={e=> set('enableLastName', e.target.checked)} />
            <FAWCheckbox label="Show Email" checked={!!item.enableEmail} onChange={e=> set('enableEmail', e.target.checked)} />
            <FAWCheckbox label="Show Phone" checked={!!item.enablePhone} onChange={e=> set('enablePhone', e.target.checked)} />
            <FAWCheckbox label="Show Date of Birth" checked={!!item.enableDOB} onChange={e=> set('enableDOB', e.target.checked)} />
            <FAWCheckbox label="Show Username" checked={!!item.enableUserName} onChange={e=> set('enableUserName', e.target.checked)} />
            <FAWCheckbox label="Show Best Time to Contact" checked={!!item.enableContactTime} onChange={e=> set('enableContactTime', e.target.checked)} />
          </div>
        </div>
      </EditorSection>
    </EditorShell>
  );
}



